window.currentLang = localStorage.getItem('app_lang') || 'hi'; // Default to Hind as per context

window.t = function (key) {
    return window.i18nData[window.currentLang][key] || key;
};

window.toggleLanguage = function () {
    window.currentLang = window.currentLang === 'en' ? 'hi' : 'en';
    localStorage.setItem('app_lang', window.currentLang);
    // Reload the current view logic handles re-rendering
    window.location.reload();
};
